import{_ as e,o as d,c as o,a4 as t}from"./chunks/framework.BhEBm8_q.js";const _=JSON.parse('{"title":"파일 추가와 권한","description":"","frontmatter":{},"headers":[],"relativePath":"02-add-files.md","filePath":"02-add-files.md"}'),i={name:"02-add-files.md"};function r(l,a,c,n,s,h){return d(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="파일-추가와-권한" tabindex="-1">파일 추가와 권한 <a class="header-anchor" href="#파일-추가와-권한" aria-label="Permalink to “파일 추가와 권한”">​</a></h1><p><em>추가 버튼과 문서 선택기</em></p><p>홈 화면 오른쪽 아래의 <code>추가</code> 버튼으로 문서를 <code>Ebook 책장</code>에 담을 수 있습니다. 다른 앱에서 공유해서 가져올 수도 있습니다(자세한 내용은 <code>공유로 가져오기</code> 참고).</p><h2 id="추가할-수-있는-포맷" tabindex="-1">추가할 수 있는 포맷 <a class="header-anchor" href="#추가할-수-있는-포맷" aria-label="Permalink to “추가할 수 있는 포맷”">​</a></h2><table tabindex="0"><thead><tr><th>종류</th><th>포맷</th></tr></thead><tbody><tr><td>문서</td><td>PDF, TXT, Markdown(<code>.md</code>/<code>.markdown</code>), HWP/HWPX</td></tr><tr><td>책</td><td>EPUB</td></tr><tr><td>만화·이미지</td><td>CBZ, CB7</td></tr></tbody></table><p><code>.md</code>와 <code>.markdown</code>은 Markdown 리더로, 일반 <code>.txt</code>는 TXT 리더로 자동 분기됩니다. TXT는 UTF-8, UTF-8 BOM, UTF-16, CP949/EUC-KR 인코딩을 자동으로 인식해 한글이 깨지지 않게 정규화합니다.</p><h2 id="추가하는-방법" tabindex="-1">추가하는 방법 <a class="header-anchor" href="#추가하는-방법" aria-label="Permalink to “추가하는 방법”">​</a></h2><ol><li>홈에서 <code>추가</code> 버튼을 누릅니다.</li><li>기기의 문서 선택기가 열리면 파일을 고릅니다.</li><li>선택한 문서가 <code>Ebook 책장</code>에 추가됩니다.</li></ol><h2 id="android-권한-saf" tabindex="-1">Android 권한 (SAF) <a class="header-anchor" href="#android-권한-saf" aria-label="Permalink to “Android 권한 (SAF)”">​</a></h2><p>Android에서는 사용자가 선택한 파일 또는 폴더 범위 안에서만 문서를 읽습니다. 폴더를 한 번 허용하면 그 범위에 한해 접근 권한이 유지되므로, 같은 폴더의 문서는 다시 고르지 않아도 됩니다.</p><h2 id="ios와-ipados-권한" tabindex="-1">iOS와 iPadOS 권한 <a class="header-anchor" href="#ios와-ipados-권한" aria-label="Permalink to “iOS와 iPadOS 권한”">​</a></h2><p>iOS에서는 문서 선택기에서 허용한 파일을 엽니다. 보안 정책상 접근 권한이 만료되면 같은 파일을 다시 선택해야 할 수 있습니다. 이때는 &quot;파일을 찾을 수 없음&quot; 대신 다시 선택 안내가 표시되며, 안내에 따라 파일이나 폴더를 다시 고르면 복구됩니다.</p><h2 id="원본은-안전하게" tabindex="-1">원본은 안전하게 <a class="header-anchor" href="#원본은-안전하게" aria-label="Permalink to “원본은 안전하게”">​</a></h2><ul><li>원본 문서는 기본적으로 앱이 직접 수정하지 않습니다.</li><li>북마크·하이라이트·주석은 원본이 아니라 앱 내부에 저장됩니다.</li><li>공유로 가져온 문서는 앱 내부 복사본으로 보관되어, 외부 원본이 사라져도 계속 열립니다.</li></ul><blockquote><p>폴더 전체를 한꺼번에 다루고 싶다면 <code>매직보관함</code>을, 다른 앱에서 보낸 자료를 담으려면 <code>공유로 가져오기</code>를 참고하세요.</p></blockquote>',15)])])}const b=e(i,[["render",r]]);export{_ as __pageData,b as default};
